mapper.select:
SELECT id, order_no, stock_direction, stock_type, supplier_id, supplier_name, maker, purchase_amount, retail_amount, operator, audit_status, audit_at, remark, created_at, updated_at, deleted FROM clinic_stock_order WHERE deleted = 0
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR stock_type LIKE CONCAT('%', #{keyword}, '%') OR supplier_name LIKE CONCAT('%', #{keyword}, '%') OR audit_status LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_stock_order
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
